using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// --- In-memory notebook ---
var notebook = new List<string>();

// --- Define tools the agent can call ---
var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWebAsync),
    AIFunctionFactory.Create(TakeNote),
    AIFunctionFactory.Create(ReadNotes),
};

// --- Build the chat client with automatic function invocation ---
using IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// --- Prompt the user for a topic ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent ---
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Given a topic you must:
        1. Search the web at least 3 times with different queries to gather diverse information.
        2. Use take_note to record key findings after each search.
        3. Call read_notes and synthesize everything into a comprehensive summary.
        Be thorough—vary your search queries to cover different angles of the topic.
        """),
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

var options = new ChatOptions { Tools = tools };
var response = await chatClient.GetResponseAsync(messages, options);

Console.WriteLine("\n📋 Research Summary\n");
Console.WriteLine(response.Text);

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------

[Description("Search the web for information. Returns the top result snippets.")]
async Task<string> SearchWebAsync(
    [Description("The search query string")] string query)
{
    Console.WriteLine($"  🌐 Searching: \"{query}\"");

    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
    http.Timeout = TimeSpan.FromSeconds(15);

    try
    {
        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";
        var html = await http.GetStringAsync(url);

        // Extract result snippets from the DuckDuckGo HTML response
        var snippets = Regex.Matches(
                html,
                @"<a class=""result__snippet""[^>]*>(.*?)</a>",
                RegexOptions.Singleline)
            .Select(m => StripHtml(m.Groups[1].Value))
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .Take(5)
            .ToList();

        if (snippets.Count == 0)
        {
            // Fallback: try extracting <span> snippets
            snippets = Regex.Matches(
                    html,
                    @"class=""result__snippet[^""]*""[^>]*>(.*?)</",
                    RegexOptions.Singleline)
                .Select(m => StripHtml(m.Groups[1].Value))
                .Where(s => s.Length > 30)
                .Take(5)
                .ToList();
        }

        return snippets.Count > 0
            ? string.Join("\n\n", snippets)
            : "No search results found. Try a different query.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

[Description("Save a research note for later reference.")]
string TakeNote(
    [Description("The note content to save")] string content)
{
    notebook.Add(content);
    Console.WriteLine($"  📝 Note saved ({notebook.Count} total)");
    return $"Note #{notebook.Count} saved successfully.";
}

[Description("Read all research notes taken so far.")]
string ReadNotes()
{
    if (notebook.Count == 0)
        return "No notes have been taken yet.";

    Console.WriteLine($"  📖 Reading {notebook.Count} note(s)");
    return string.Join("\n---\n",
        notebook.Select((n, i) => $"Note {i + 1}:\n{n}"));
}

// --- Helpers ---

static string StripHtml(string html) =>
    WebUtility.HtmlDecode(Regex.Replace(html, "<.*?>", "")).Trim();

